P0_SEA_LEVEL = 101325
ALTITUDE_SCALING = 44330
EXPONENT = 1 / 5.255

def get_altitude(pressure):
    if not 0 <= pressure <= P0_SEA_LEVEL:
        return 0.0
    ratio = pressure / P0_SEA_LEVEL
    return ALTITUDE_SCALING * (1 - ratio**EXPONENT)

if __name__ == "__main__":
    print(f"Altitude: {get_altitude(100000)} m")
